begin;
alter table public.marketplace_reviews add column if not exists helpful_count integer not null default 0 check (helpful_count>=0), add column if not exists is_hidden boolean not null default false, add column if not exists moderation_note text;
create table if not exists public.marketplace_review_votes (review_id uuid not null references public.marketplace_reviews(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,created_at timestamptz not null default now(),primary key(review_id,user_id));
create table if not exists public.marketplace_review_reports (id uuid primary key default gen_random_uuid(),review_id uuid not null references public.marketplace_reviews(id) on delete cascade,reporter_id uuid not null references auth.users(id) on delete cascade,reason text not null check(reason in('spam','abuse','misleading','personal_information','other')),details text not null check(char_length(trim(details)) between 10 and 1000),status text not null default 'open' check(status in('open','reviewing','resolved','dismissed')),reviewed_by uuid references auth.users(id) on delete set null,reviewed_at timestamptz,created_at timestamptz not null default now(),unique(review_id,reporter_id));
alter table public.marketplace_review_votes enable row level security;alter table public.marketplace_review_reports enable row level security;
drop policy if exists "Users can view review votes" on public.marketplace_review_votes;create policy "Users can view review votes" on public.marketplace_review_votes for select using(true);
drop policy if exists "Users can vote reviews" on public.marketplace_review_votes;create policy "Users can vote reviews" on public.marketplace_review_votes for insert to authenticated with check(user_id=auth.uid());
drop policy if exists "Users can remove own review vote" on public.marketplace_review_votes;create policy "Users can remove own review vote" on public.marketplace_review_votes for delete to authenticated using(user_id=auth.uid());
drop policy if exists "Users can submit review reports" on public.marketplace_review_reports;create policy "Users can submit review reports" on public.marketplace_review_reports for insert to authenticated with check(reporter_id=auth.uid());
drop policy if exists "Users can view own review reports" on public.marketplace_review_reports;create policy "Users can view own review reports" on public.marketplace_review_reports for select to authenticated using(reporter_id=auth.uid() or public.current_user_role()='admin');
grant select,insert,delete on public.marketplace_review_votes to authenticated;grant select,insert on public.marketplace_review_reports to authenticated;
create or replace function public.refresh_review_helpful_count() returns trigger language plpgsql security definer set search_path=public as $$ begin update public.marketplace_reviews set helpful_count=(select count(*) from public.marketplace_review_votes where review_id=coalesce(new.review_id,old.review_id)) where id=coalesce(new.review_id,old.review_id);return coalesce(new,old);end;$$;
drop trigger if exists marketplace_review_vote_metrics on public.marketplace_review_votes;create trigger marketplace_review_vote_metrics after insert or delete on public.marketplace_review_votes for each row execute function public.refresh_review_helpful_count();
commit;
